#!/usr/bin/env python3
import json, random, re
from pwn import remote
from Crypto.Util.number import bytes_to_long, long_to_bytes, getPrime

HOST='crypto.chal.csaw.io'; PORT=32333

class LostMindClient:
    def __init__(self, host=HOST, port=PORT, off=0, ln=1):
        self.r = remote(host, port)
        self._recv_until(b'offset,len:')
        self._send_line(f"{off},{ln}".encode())
        line = self._recv_line().decode(errors='ignore').strip()
        m = re.search(r'encrypted flag:\s*([0-9a-fA-F]+)', line); assert m
        self.C = int(m.group(1), 16)
        line2 = self._recv_line().decode(errors='ignore').strip()
        m2 = re.search(r'you got\s+(\d+)\s+rounds', line2); assert m2
        self.rounds = int(m2.group(1)); self.used = 0
    def _recv_until(self, t): return self.r.recvuntil(t, timeout=5)
    def _recv_line(self): return self.r.recvline(timeout=5)
    def _send_line(self, b): self.r.send(bytes(b)+b'\n')
    def _menu(self, ch):
        self._recv_until(b'1. encrypt'); self._recv_until(b'2. decrypt'); self._recv_until(b'====================================')
        self._send_line(ch); self.used += 1
    def encrypt(self, msg: bytes) -> int:
        self._menu(b'1'); self._recv_until(b'input:'); self._send_line(msg); return int(self._recv_line().strip(),16)
    def decrypt_low(self, cbytes: bytes) -> int:
        self._menu(b'2'); self._recv_until(b'input:'); self._send_line(cbytes); return int(self._recv_line().strip(),16)
    def close(self): self.r.close()

def b_of_int(x): return b'\x00' if x==0 else long_to_bytes(x)

def protocol_self_checks():
    c = LostMindClient(off=0, ln=1); detail={}
    try:
        x = bytes(random.getrandbits(8) for _ in range(random.randint(1,4)))
        ex = c.encrypt(x); dx = c.decrypt_low(b_of_int(ex)); ok_a = (dx==x[-1])
        a,b = random.randrange(1,1<<16), random.randrange(1,1<<16)
        ea,eb,eab = c.encrypt(b_of_int(a)), c.encrypt(b_of_int(b)), c.encrypt(b_of_int(a*b))
        lhs, rhs = c.decrypt_low(b_of_int(ea*eb)), c.decrypt_low(b_of_int(eab)); ok_b=(lhs==rhs)
        detail={'check_a':{'x_hex':x.hex(),'enc_hex':hex(ex),'dec_low':dx,'expected':x[-1],'pass':ok_a},'check_b':{'a':a,'b':b,'lhs':lhs,'rhs':rhs,'pass':ok_b},'used_rounds':c.used}
        return ok_a and ok_b, detail
    finally:
        c.close()

def collect_dataset(max_shift=40):
    cli = LostMindClient(off=0, ln=1)
    data={'C':cli.C,'rounds':cli.rounds,'samples':[],'shift_samples':{},'r0':None}
    try:
        data['r0']=cli.decrypt_low(b_of_int(cli.C))
        for j in range(max_shift+1):
            if cli.used+2>cli.rounds: break
            t=1<<j; et=cli.encrypt(b_of_int(t)); s=cli.decrypt_low(b_of_int(cli.C*et)); data['shift_samples'][str(j)]={'t':t,'s':s}
        while cli.used+2<=cli.rounds:
            t=(random.randrange(1,1<<24)|1); et=cli.encrypt(b_of_int(t)); r=cli.decrypt_low(b_of_int(cli.C*et)); data['samples'].append({'t':t,'r':r})
        data['used_rounds']=cli.used
    finally:
        cli.close()
    return data

def attack_mod256(data):
    m0=data['r0']; surv=[]
    for n0 in range(1,256,2):
        good=True
        for s in data['samples']:
            want=(m0*(s['t']&0xff)-s['r'])&0xff
            if not any(((k*n0)&0xff)==want for k in range(256)): good=False; break
        if good: surv.append(n0)
    return surv

def toy_smt_feasibility(num_eq=14, bits=32):
    from z3 import Int, Solver
    # Simulate smaller RSA-like relation r_i = (M*t_i - K_i*N) mod 256
    p,q=getPrime(bits//2),getPrime(bits//2)
    N=p*q; M=random.randrange(2, N-1)
    tvals=[random.randrange(1,1<<16)|1 for _ in range(num_eq)]
    rs=[]; ks=[]
    for t in tvals:
        v=M*t
        k=v//N
        ks.append(k)
        rs.append((v-k*N)&0xff)

    # recover N mod 2^16 and M mod 2^16 with bounded carries and hidden u_i
    MOD=1<<16
    n16=Int('n16'); m16=Int('m16'); s=Solver()
    s.add(n16>=1, n16<MOD, n16%2==1, m16>=0, m16<MOD, m16%256==M%256)
    K=[];U=[]
    for i,(t,r) in enumerate(zip(tvals,rs)):
        ki=Int(f'k{i}'); ui=Int(f'u{i}')
        K.append(ki); U.append(ui)
        s.add(ki>=0, ki<=t)
        s.add(ui>=0, ui<256)
        s.add((m16*(t%MOD) - ki*n16 - (r + 256*ui)) % MOD == 0)
    ok = s.check().r == 1
    model=None
    if ok:
        md=s.model(); model={'n16':md[n16].as_long(), 'm16':md[m16].as_long(), 'true_n16':N%MOD, 'true_m16':M%MOD}
    return {'sat':ok,'model':model,'true_low8_m':M%256}

if __name__=='__main__':
    passed, details = protocol_self_checks()
    data = collect_dataset(40)
    surv = attack_mod256(data)
    toy = toy_smt_feasibility()
    report={
        'protocol_passed':passed,'protocol_details':details,
        'num_samples':len(data['samples']),'num_shift_samples':len(data['shift_samples']),
        'surviving_n_mod256':surv,'survivor_count_mod256':len(surv),
        'toy_smt':toy
    }
    with open('/home/ctfplayer/ctf_files/dataset_step3.json','w') as f: json.dump({'dataset':data,'report':report},f,indent=2)
    print(json.dumps(report,indent=2))

